---@class LxAtlasLoadTask
local LxAtlasLoadTask = classX("LxAtlasLoadTask", nil)

local TASK_LIMIT_COUNT = 4

local InvokeCallback = InvokeCallback

local AtlasLoadState = {
    Stop = 0,
    Running = 1
}

function LxAtlasLoadTask:Initialize()
    self._loadState = AtlasLoadState.Stop

    ---@type string[]
    self._dataList = {}

    ---@type LxAtlasAsset[]
    self._atlasList = {}
end

function LxAtlasLoadTask:Dispose()

    self:ReleaseAtlasList()

    self._loadedOk = nil
    self._cbProcess = nil
    self._cbObject = nil
    self._dataList = nil
    self._loadState = AtlasLoadState.Stop
end

function LxAtlasLoadTask:ReleaseAtlasList()
    local atlasList = self._atlasList
    local len =  #atlasList
    while len > 0 do
        local data = table.remove(atlasList)
        if not data:IsDisposed() then
            data:Release()
            if data:IsLoading() then
                data:RemoveRequestAtlasCb(self.OnLoadSingleOk, self)
            end
        end
        len = len - 1
    end
end


function LxAtlasLoadTask:InitTask(loadedOk, cbProcess, cbObj)
    if self._loadState ~= AtlasLoadState.Stop then return end
    self._loadedOk = loadedOk
    self._cbProcess = cbProcess
    self._cbObject = cbObj

    ---@type string[]
    self._dataList = {}

    self:ReleaseAtlasList()
end

---@param assetPath string @资源路径
function LxAtlasLoadTask:AddData(assetPath)
    if self._loadState ~= AtlasLoadState.Stop then return end
    table.insert(self._dataList, assetPath)
end

function LxAtlasLoadTask:StartTask()
    if self._loadState == AtlasLoadState.Stop then
        self._loadState = AtlasLoadState.Running
        self._refIndex = 0
        self._refCount = #self._dataList
        self._loadCount = 0
        self._taskCount = 0

        if self._refCount == 0 then
            if LOG_INFO_ENABLED then
                printInfo("AtlasLoad", "not AtlasLoad data , Finished AtlasLoad Immediate!!!");
            end
            self:OnLoadOk()
            return
        end

        for _k=1, TASK_LIMIT_COUNT do
            self:LoadNext()
        end
    end
end

function LxAtlasLoadTask:LoadNext()
    if self._isDisposed then return end

    if self._loadCount >= self._refCount then
        return
    end
    if self._taskCount >= TASK_LIMIT_COUNT then
        return
    end

    self._loadCount = self._loadCount + 1
    local data = table.remove(self._dataList, 1)
    self._taskCount = self._taskCount + 1

    local atlas = MgrCenter.ComponentMgr:CreateAtlas(data)
    if atlas then
        table.insert(self._atlasList, atlas)
        atlas:AddRef()
        if atlas:IsLoading() then
            atlas:AddRequestAtlasCb(self.OnLoadSingleOk, self)
        else
            self:OnLoadSingleOk(atlas)
        end
    else
        self:OnLoadSingleOk(atlas)
    end
end

function LxAtlasLoadTask:OnLoadSingleOk(atlas)
    if self._isDisposed then
        return
    end

    self._taskCount = self._taskCount - 1
    self._refIndex = self._refIndex + 1

    if self._cbProcess then
        InvokeCallback(self._cbProcess, self._cbObject, self._refIndex, self._refCount)
    end

    if self._refIndex >= self._refCount then
        self:OnLoadOk()
    elseif self._loadCount < self._refCount then
        self:LoadNext()
    end

    return true
end

function LxAtlasLoadTask:OnLoadOk()
    local loadedOk = self._loadedOk
    local cbObject = self._cbObject

    self._loadedOk = nil
    self._cbProcess = nil
    self._cbObject = nil
    self._dataList = nil
    self._loadState = AtlasLoadState.Stop

    if loadedOk ~= nil then
        InvokeCallback(loadedOk, cbObject)
    end
end

return LxAtlasLoadTask